import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  const [file, setFile] = useState(null);
  const [subIds, setSubIds] = useState('');
  const [loading, setLoading] = useState(false);
  const [brands, setBrands] = useState({});
  const [selectedBrand, setSelectedBrand] = useState('');
  const [selectedSubsidy, setSelectedSubsidy] = useState('');
  const [filterColumnName, setFilterColumnName] = useState('');
  const [previewData, setPreviewData] = useState(null);
  const [selectedSheet, setSelectedSheet] = useState(0);

  useEffect(() => {
    // Fetch available brands and their columns
    axios.get('http://localhost:3001/excel/brands')
      .then(response => {
        setBrands(response.data);
      })
      .catch(error => {
        console.error('Error fetching brands:', error);
      });
  }, []);

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
    setPreviewData(null); // Reset preview when new file is selected
  };

  const handleBrandChange = (e) => {
    setSelectedBrand(e.target.value);
    setSelectedSubsidy(''); // Reset subsidy when brand changes
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!file || !subIds) {
      alert('Please upload a file and enter IDs');
      return;
    }

    setLoading(true);
    const formData = new FormData();
    formData.append('file', file);
    formData.append('subIds', subIds);
    formData.append('brand', selectedBrand);
    formData.append('subsidyColumn', selectedSubsidy);
    formData.append('filterColumnName', filterColumnName);

    try {
      const response = await axios.post('http://localhost:3001/excel/upload', formData);
      setPreviewData(response.data);
      setSelectedSheet(0);
    } catch (error) {
      alert('Error processing file: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const handleDownload = async () => {
    try {
      const response = await axios.post('http://localhost:3001/excel/download', 
        { data: previewData },
        { responseType: 'blob' }
      );

      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', 'filtered_results.xlsx');
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (error) {
      alert('Error downloading file: ' + error.message);
    }
  };

  const handleDownloadSheet = async (sheetIndex) => {
    try {
      const singleSheetData = {
        sheets: [previewData.sheets[sheetIndex]],
        hasData: true
      };

      const response = await axios.post('http://localhost:3001/excel/download', 
        { data: singleSheetData },
        { responseType: 'blob' }
      );

      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `${previewData.sheets[sheetIndex].name}.xlsx`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (error) {
      alert('Error downloading sheet: ' + error.message);
    }
  };

  const availableColumns = selectedBrand ? brands[selectedBrand] || [] : [];
  const subsidyColumns = availableColumns.filter(col => 
    col.toLowerCase().includes('subsidy')
  );

  return (
    <div className="App">
      <div className="container">
        <h1>Excel Validator</h1>
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Upload Excel File:</label>
            <input 
              type="file" 
              accept=".xlsx,.xls" 
              onChange={handleFileChange}
            />
          </div>
          
          <div className="form-group">
            <label>Filter Column Name (Optional):</label>
            <input 
              type="text" 
              value={filterColumnName}
              onChange={(e) => setFilterColumnName(e.target.value)}
              placeholder="e.g., SubID, ExtraParam, CustomField"
            />
            <small style={{color: '#666', fontSize: '12px'}}>
              Leave empty to auto-detect (SubID, ExtraParam, etc.)
            </small>
          </div>

          <div className="form-group">
            <label>Enter IDs (comma-separated):</label>
            <input 
              type="text" 
              value={subIds}
              onChange={(e) => setSubIds(e.target.value)}
              placeholder="e.g., 101, 102, 103"
            />
          </div>

          <div className="form-group">
            <label>Select Brand:</label>
            <select value={selectedBrand} onChange={handleBrandChange}>
              <option value="">-- Select Brand --</option>
              {Object.keys(brands).map(brand => (
                <option key={brand} value={brand}>{brand}</option>
              ))}
            </select>
          </div>

          {selectedBrand && subsidyColumns.length > 0 && (
            <div className="form-group">
              <label>Select Subsidy Column (Optional):</label>
              <select 
                value={selectedSubsidy} 
                onChange={(e) => setSelectedSubsidy(e.target.value)}
              >
                <option value="">-- No Subsidy Filter --</option>
                {subsidyColumns.map(col => (
                  <option key={col} value={col}>{col}</option>
                ))}
              </select>
            </div>
          )}

          <button type="submit" disabled={loading}>
            {loading ? 'Processing...' : 'Preview Results'}
          </button>
        </form>

        {previewData && previewData.sheets && previewData.sheets.length > 0 && (
          <div className="preview-section">
            <h2>Preview Results</h2>
            
            <div className="download-all-section">
              <button type="button" className="download-all-btn" onClick={handleDownload}>
                📥 Download All Sheets (Excel File)
              </button>
            </div>

            <div className="sheet-tabs">
              {previewData.sheets.map((sheet, index) => (
                <button
                  key={index}
                  type="button"
                  className={selectedSheet === index ? 'tab active' : 'tab'}
                  onClick={() => setSelectedSheet(index)}
                >
                  {sheet.name} ({sheet.data.length} rows)
                </button>
              ))}
            </div>
            
            <div className="sheet-preview">
              <div className="sheet-header">
                <h3>{previewData.sheets[selectedSheet]?.name}</h3>
                <button 
                  type="button" 
                  className="download-sheet-btn" 
                  onClick={() => handleDownloadSheet(selectedSheet)}
                >
                  📥 Download This Sheet
                </button>
              </div>

              <div className="table-container">
                <table>
                  <thead>
                    <tr>
                      {previewData.sheets[selectedSheet] && 
                       previewData.sheets[selectedSheet].data.length > 0 &&
                        Object.keys(previewData.sheets[selectedSheet].data[0]).map((key) => (
                          <th key={key}>{key}</th>
                        ))}
                    </tr>
                  </thead>
                  <tbody>
                    {previewData.sheets[selectedSheet] && 
                     previewData.sheets[selectedSheet].data.map((row, idx) => (
                      <tr key={idx}>
                        {Object.values(row).map((value, i) => (
                          <td key={i}>{String(value)}</td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
